func TestEnumWebhookStatus(t *testing.T) {
	t.Run("NewFromString_enabled", func(t *testing.T) {
		t.Parallel()
		val, err := NewWebhookStatusFromString("enabled")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, WebhookStatus("enabled"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_disabled", func(t *testing.T) {
		t.Parallel()
		val, err := NewWebhookStatusFromString("disabled")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, WebhookStatus("disabled"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewWebhookStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewWebhookStatusFromString("enabled")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

func TestExtraPropertiesWebhook(t *testing.T) {
	t.Run("GetExtraProperties", func(t *testing.T) {
		t.Parallel()
		obj := &Webhook{}
		// Should not panic when calling GetExtraProperties()
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("GetExtraProperties() panicked: %v", r)
			}
		}()
		extraProps := obj.GetExtraProperties()
		// Result can be nil or an empty/non-empty map
		_ = extraProps
	})

	t.Run("GetExtraProperties_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *Webhook
		extraProps := obj.GetExtraProperties()
		assert.Nil(t, extraProps, "nil receiver should return nil without panicking")
	})
}

